"""
MKT Original Commentary — Genesis chapters 13–16
Run: python3 scripts/zc-original-genesis-13-16.py

Source data used:
- data/interlinear/genesis.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/genesis.json (MKT text)

Key decisions:
- Ch 13: eastward movement (qeḏem) is read as theologically laden — consistently
  in Genesis the east marks departure from the presence of God (3:24; 4:16; 11:2);
  Lot's choice echoes Adam's and Cain's
- Ch 14: haʿiḇrî (the Hebrew, 14:13) is the first use of this label for Abram;
  treated as an external designator, not a self-chosen ethnic identity
- Ch 14: Melchizedek's dual role (king + priest) and El Elyon identified with YHWH
  by Abram in v22 — the MKT preserves the divine-name identification without
  harmonizing; commentary follows that identification without speculating about
  Canaanite religion
- Ch 15:6 is already present in the output file; skipped in this dictionary
- Ch 15: the covenant ceremony (vv. 9-17) emphasizes the unilateral divine passage
  — only God moves between the pieces; Abram is asleep; the covenantal obligation
  is entirely on God's side, which is the grammar of grace
- Ch 16: malʾaḵ YHWH is discussed as a complex figure without resolving the angel
  vs. theophany question; Hagar's naming of God is treated as a unique event
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS = {
  "13": {
    "1": '<p><strong>וַיַּעַל אַבְרָם מִמִּצְרַיִם</strong> (<em>wayyaʿal ʾaḇrām mimmitsrāyim</em>) — "Abram went up from Egypt." <em>ʿĀlāh</em> (Qal waw-consecutive, to go up, ascend) — directional language that is topographically precise: Canaan is higher than the Nile Delta, so one always "goes up" from Egypt to Canaan. But in the OT the verb carries canonical weight beyond geography: going up to Canaan and going up to Jerusalem become theological movements (Ezra 1:3; 2:1; the post-exilic returns are all described with <em>ʿālāh</em>). Abram\'s return from Egypt with his wife and wealth complete (unlike the Egypt episode in ch. 12) signals restoration of the narrative that the famine had temporarily suspended.</p>',
    "2": '<p><strong>כָּבֵד מְאֹד בַּמִּקְנֶה בַּכֶּסֶף וּבַזָּהָב</strong> (<em>kāḇēḏ mĕʾōḏ bammiqneh bakkeseḵ ûḇazzāhāḇ</em>) — "very heavy/weighty in livestock and in silver and gold." <em>Kāḇēḏ</em> (heavy, weighty) is the standard word for being wealthy or laden — the same root as <em>kāḇôḏ</em> (glory, honor, weightiness). The semantic field connects material wealth and social honor: to be heavy with goods is to be "glorious" in the eyes of the ancient world. The enumeration of livestock, silver, and gold will recur in the patriarchal wealth-formulas (24:35; 26:14) — the MKT reflects the material texture of ANE pastoral economics.</p>',
    "3": '<p><strong>לְמַסָּעָיו</strong> (<em>lĕmasāʿāyw</em>, by his stages/journeys) — from <em>nāsaʿ</em> (to pull up tent stakes and set out; to journey by stages). The noun <em>massāʿ</em> (journey stage, stopping place) appears most densely in Numbers 33, where Israel\'s wilderness journey is recorded as a list of <em>massāʾôt</em> (stopping-places). Abram\'s return to Bethel stage by stage echoes the wilderness wandering — the patriarchal sojourn and the Sinai sojourn are structurally parallel. <strong>בֵּין בֵּית-אֵל וּבֵין הָעַי</strong> — the specific geography (between Bethel and Ai) marks the exact altar site from 12:8, completing the journey circle.</p>',
    "4": '<p><strong>שֵׁם יְהוָה</strong> (<em>šēm YHWH</em>, the name of the LORD) — calling on the name of YHWH is the worship formula introduced in 4:26 (Enosh\'s generation "began to call on the name of the LORD") and repeated at each of Abram\'s altar sites (12:8; here; 21:33). The act of calling on the name is covenantal and public — it marks a site as belonging to YHWH\'s sphere. Abram returns to the Bethel altar after the Egypt episode: the lapse of ch. 12 is not the end of the story; the worship resumes. The Hebrew idiom <em>qārāʾ bĕšēm YHWH</em> includes the idea of proclaiming the name — invoking YHWH publicly over the landscape.</p>',
    "5": '<p><strong>גַּם-לְלוֹט</strong> (<em>gam-lĕlôṭ</em>, also to Lot) — Lot is syntactically included within Abram\'s orbit: "also to Lot, who was going with Abram." <em>Hahōlēḵ ʾet-ʾaḇrām</em> (the one going with Abram) — the Qal participle presents Lot\'s accompanying as continuous. Lot has flocks, herds, and tents of his own — wealth accumulated during the Egypt sojourn (sharing Abram\'s blessing by proximity). The abundance of both men is what creates the conflict in v. 6.</p>',
    "6": '<p><strong>לֹא-נָשָׂא אֹתָם הָאָרֶץ</strong> (<em>lōʾ-nāśāʾ ʾōtām hāʾāreṣ</em>) — "the land was not able to support them." <em>Nāśāʾ</em> (to carry, bear, lift) — the land literally "could not carry/bear them together." The same idiom appears in 36:7 for Esau and Jacob. The conflict of abundance is a land-carrying issue — the pastoral economy of the ancient Near East required vast territory for grazing herds; the land\'s limit forces the partition that the next verses describe.</p>',
    "7": '<p><strong>וַיְהִי-רִיב</strong> (<em>wayhî-rîḇ</em>, and there was strife) — <em>rîḇ</em> is the legal/adversarial dispute word: a case, a lawsuit, a controversy (cf. Micah 6:1: "the LORD has a <em>rîḇ</em> with his people"). Even though here it is between herdsmen, the term elevates a pastoral dispute to a quasi-legal conflict. <strong>הַכְּנַעֲנִי וְהַפְּרִזִּי אָז יֹשֵׁב בָּאָרֶץ</strong> — the parenthetical note about Canaanites and Perizzites in the land reminds the reader that Abram and Lot are resident aliens (<em>gērîm</em>) — their conflict risks dishonoring YHWH\'s name before the eyes of the land\'s actual occupants.</p>',
    "8": '<p><strong>אַל-נָא תְהִי מְרִיבָה</strong> (<em>ʾal-nāʾ tĕhî mĕrîḇāh</em>) — "let there not be strife." <em>ʾAl</em> (negative jussive) + <em>nāʾ</em> (please, I pray) — gentle entreaty rather than command; Abram defers to his nephew out of love rather than asserting the senior\'s claim. <em>Mĕrîḇāh</em> (strife, contention) — the same word as the water-strife site in the wilderness (Exod 17:7; Num 20:13). <strong>כִּי-אֲנָשִׁים אַחִים אֲנָחְנוּ</strong> — "for we are brothers/kinsmen." <em>ʾAḥîm</em> means kinsmen broadly (uncle-nephew, cousins — not just sibling brothers). The kinship claim is the moral ground for peace: family should not fight.</p>',
    "9": '<p><strong>הֲלֹא כָל-הָאָרֶץ לְפָנֶיךָ</strong> (<em>hălōʾ ḵol-hāʾāreṣ lĕpānêḵā</em>) — "Is not the whole land before you?" The rhetorical question gives Lot the choice — Abram, the elder, cedes his priority right. <strong>אִם-הַשְּׂמֹאל וְאֵימִנָה</strong> (if left, I will go right; if right, I will go left) — the ABBA chiastic structure of the direction-offer encodes Abram\'s complete openness. The generosity is remarkable: Abram, the covenant recipient, gives up the right of first selection to preserve family peace. This deference contrasts with the grasping mentality of Babel and Lot\'s subsequent choice.</p>',
    "10": '<p><strong>כִּכַּר הַיַּרְדֵּן כִּי כֻלָּהּ מַשְׁקֶה</strong> (<em>kikkar hayyardēn kî ḵullāh mašqeh</em>) — "the whole plain of the Jordan, for all of it was well-watered." <em>Kikkar</em> (the round/circular area, the plain) — the Jordan Valley. <em>Mašqeh</em> (well-watered, irrigated) from <em>šāqāh</em> (to water, give to drink).</p><p><strong>כְּגַן-יְהוָה כְּאֶרֶץ מִצְרַיִם</strong> — "like the garden of the LORD, like the land of Egypt." Two comparisons: Eden (the garden of the LORD, cf. 2:8-10) and Egypt (the Nile irrigation, 12:10). Both carry ominous resonance: the garden is where humanity was expelled from; Egypt is where Abram nearly lost Sarai. The most desirable territory in Lot\'s eyes is associated with exile and the foreign. The narrator\'s proleptic "before the LORD destroyed Sodom and Gomorrah" signals the fatal irony: Lot is choosing what looks like paradise, which will become destruction.</p>',
    "11": '<p><strong>וַיִּסַּע לוֹט מִקֶּדֶם</strong> (<em>wayyissaʿ lôṭ miqqeḏem</em>) — "Lot set out eastward." <em>Qeḏem</em> (east, the direction of the rising sun) carries the narrative weight of departure throughout Genesis: the expulsion from Eden is eastward (3:24); Cain goes east (4:16); Babel is in the east (11:2). Lot\'s eastward movement falls into this pattern — east marks movement away from the presence of God and toward the region of judgment. The text\'s structural use of <em>qeḏem</em> is not coincidental.</p>',
    "12": '<p><strong>אַבְרָם יָשַׁב בְּאֶרֶץ-כְּנָעַן וְלוֹט יָשַׁב בְּעָרֵי הַכִּכָּר</strong> — the two men\'s destinations are contrasted in a single verse: Abram in the land of Canaan (the promise); Lot among the cities of the plain. <strong>וַיֶּאֱהַל עַד-סְדֹם</strong> — "and pitched his tents as far as Sodom." <em>ʾĀhal</em> (to tent, to pitch a tent) — Lot gradually approaches Sodom; in 14:12 he is "living in Sodom"; in 19:1 he is "sitting at the gate of Sodom" (a position of civic leadership). The progressive enculturation into Sodom happens in stages, tracked by these verbal notices.</p>',
    "13": '<p><strong>וְאַנְשֵׁי סְדֹם רָעִים וְחַטָּאִים לַיהוָה מְאֹד</strong> — "now the men of Sodom were wicked and sinners against the LORD exceedingly." Two near-synonyms pile up: <em>rāʿîm</em> (wicked, evil — the general moral category) and <em>ḥaṭṭāʾîm</em> (sinners — those who miss the mark, <em>ḥāṭāʾ</em>). The intensifier <em>mĕʾōḏ</em> (greatly, exceedingly) at the end is emphatic. The phrase <em>laYHWH</em> (against the LORD) frames their wickedness as transgression against the covenant God specifically, not merely against social norms. This verse sets the stage for the divine inspection and judgment of chs. 18-19.</p>',
    "14": '<p><strong>שָׂא עֵינֶיךָ וּרְאֵה מִן-הַמָּקוֹם אֲשֶׁר-אַתָּה שָׁם</strong> — "lift up your eyes and look from the place where you are." The command <em>śāʾ ʿênêḵā</em> (lift your eyes) is the standard prelude to a divinely directed seeing-event throughout the patriarchal narratives (13:14; 18:2; 22:4, 13; 24:63; 31:10, 12; 33:1). Immediately after Lot departs, YHWH speaks to Abram — the covenant promise restated. The land promise is now given not merely for offspring (12:7) but directly to Abram\'s sight: "all the land that you see I will give to you." The land is visualized before it is possessed.</p>',
    "15": '<p><strong>כִּי אֶת-כָּל-הָאָרֶץ אֲשֶׁר-אַתָּה רֹאֶה לְךָ אֶתְּנֶנָּה וּלְזַרְעֲךָ עַד-עוֹלָם</strong> — "for all the land that you see, to you I will give it and to your offspring forever." <em>ʿAḏ-ʿôlām</em> (forever, unto eternity) — this is the perpetual/eternal form of the land covenant: the promised possession is not temporary. <em>ʿÔlām</em> (long duration, age, perpetuity) — when applied to the covenant (17:7, 8, 13, 19; Exod 31:16-17), it carries the force of an irrevocable divine commitment that transcends any single generation. Remarkably, this unconditional promise comes immediately after Lot has chosen the best land — YHWH gives Abram what Lot visually appropriated.</p>',
    "16": '<p><strong>וְשַׂמְתִּי אֶת-זַרְעֲךָ כַּעֲפַר הָאָרֶץ</strong> — "I will make your offspring like the dust of the earth." The dust metaphor for innumerability (here) complements the star metaphor of 15:5 and the sand metaphor of 22:17. Each image emphasizes a different dimension: dust = ubiquitous, earth-covering (geographic spread); stars = sublime, heaven-reaching (transcendence); sand = borderline, coastal (the seashore of promise). <em>ʿĀpār hāʾāreṣ</em> (dust of the earth) echoes Adam\'s creation from the dust (2:7) and Adam\'s return to dust (3:19) — the offspring who will be as dust are those formed from the dust, a subtle human-solidarity image.</p>',
    "17": '<p><strong>קוּם הִתְהַלֵּךְ בָּאָרֶץ לְאָרְכָּהּ וּלְרָחְבָּהּ</strong> — "arise, walk through the land in its length and in its breadth." <em>Hitchallēḵ</em> (Hithpael of <em>hālak</em>, walk about through) — the Hithpael denotes reciprocal or intensive walking, traversing completely. This same form appears in 17:1 (God\'s command to "walk before me") and 5:22, 24 (Enoch "walked with God"). Walking through the land is a symbolic act of possession — traversing the territory claims it (cf. Josh 1:3: "every place your foot treads I will give to you"). The command anticipates Joshua\'s reconnaissance of the land; Abram is to survey what is promised.</p>',
    "18": '<p><strong>אֵלֹנֵי מַמְרֵא אֲשֶׁר בְּחֶבְרוֹן</strong> — "the oaks of Mamre which are at Hebron." <em>ʾĒlônê mamrēʾ</em> (oaks/terebinths of Mamre) — the great trees site at Hebron; Mamre is an Amorite chieftain allied with Abram (14:13, 24). Abram settles at the site of his Amorite ally, near sacred trees. <em>Ḥeḇrôn</em> (Hebron) — the name may be connected to the root <em>ḥāḇar</em> (to join, to be allied/confederate) — "fellowship" — apt for a place where Abram lives among allied Amorites. Hebron will be the site of Sarah\'s burial (23:19), Abram\'s burial (25:9), and Israel\'s first royal capital under David (2 Sam 2:3-4). <strong>מִזְבֵּחַ לַיהוָה</strong> — another altar, the fourth in Abram\'s worship-marking of the land (12:7, 8; 13:4; here).</p>'
  },
  "14": {
    "1": '<p>The narrative opens with a list of four kings who form the imperial coalition: <strong>אַמְרָפֶל</strong> (<em>Amrāpel</em>, Amraphel) king of Shinar (= Babylonia, cf. 10:10; 11:2); <strong>אַרְיוֹךְ</strong> (<em>ʾAryôḵ</em>, Arioch) king of Ellasar; <strong>כְּדָרְלָעֹמֶר</strong> (<em>Kĕḏarlāʿomer</em>, Kedorlaomer) king of Elam — an Elamite compound name meaning "servant of [the god] Lagamar"; <strong>תִּדְעָל</strong> (<em>Tiḏʿāl</em>, Tidal) king of nations (<em>gôyim</em>). The historical identification of these kings with specific ancient rulers is debated; the narrative does not depend on the identifications. What matters is the geopolitical scope: the eastern imperial coalition spans from Babylonia to Elam.</p>',
    "2": '<p>The five Canaanite kings of the plain include <strong>בֶּרַע</strong> (<em>Beraʿ</em>, Bera) king of Sodom and <strong>בִּרְשַׁע</strong> (<em>Biršaʿ</em>, Birsha) king of Gomorrah — both names may pun on Hebrew moral terms: <em>beraʿ</em> ("in evil") and <em>biršaʿ</em> ("in wickedness") — the narrator may be encoding the moral character of Sodom and Gomorrah\'s kings in their names, though this is debated as a wordplay vs. actual Semitic names. The city list (Sodom, Gomorrah, Admah, Zeboiim, Bela/Zoar) is the pentapolis of the plain, the same cities mentioned in 10:19 and whose destruction is narrated in 19:24-25.</p>',
    "3": '<p><strong>עֵמֶק הַשִּׂדִּים הוּא יָם הַמֶּלַח</strong> — "the valley of Siddim, that is, the Salt Sea." The parenthetical identification equates the Valley of Siddim with the Dead Sea — the narrator writes from a post-destruction perspective, when the valley (once fertile, 13:10) has become the Salt Sea. The five city-plain is now underwater. This geographic parenthetical functions as a proleptic epitaph: even before the battle is described, the reader knows the valley ceased to exist.</p>',
    "4": '<p><strong>שְׁתֵּים עֶשְׂרֵה שָׁנָה עָבְדוּ אֶת-כְּדָרְלָעֹמֶר</strong> — "twelve years they served Kedorlaomer, and in the thirteenth year they rebelled." The twelve-year submission and thirteenth-year rebellion provides the political context: the Canaanite pentapolis had been vassals of the Elamite king. The fourteenth year brings the punitive campaign. The numbers (12/13/14) track the years precisely — unusual specificity that signals either archival source material or deliberate literary framing of the event as a genuine historical incident within the patriarchal period.</p>',
    "5": '<p><strong>הָרְפָאִים</strong> (<em>hārĕpāʾîm</em>, the Rephaim) — "the ancient ones/mighty ones"; these pre-Israelite giants appear throughout the OT (Deut 2:10-11, 20-21; 3:11; Josh 12:4; 13:12; 17:15; 1 Chron 20:4-8). The Rephaim were associated with both ancient pre-Canaanite peoples and with the shades of the dead in Sheol (Isa 14:9; 26:14; Ps 88:10; Job 26:5). The campaign sweeps through the entire Transjordanian territory, clearing out ancient peoples — the coalition\'s military reach is comprehensive and the narrative emphasizes the scope of their conquest before Abram enters the story.</p>',
    "6": '<p><strong>הַחֹרִי בְּהַרֵרָם שֵׂעִיר</strong> — "the Horites in their mountain territory of Seir." The Horites (<em>ḥōrî</em>, cave-dwellers?) are the pre-Edomite inhabitants of the Seir region (Deut 2:12, 22), displaced by Esau\'s descendants. The campaign route sweeps south through the Transjordan, then curves back north — a military encirclement strategy that allows the eastern coalition to strike the southern Canaanite cities from the rear after isolating them geographically.</p>',
    "7": '<p><strong>עֵין מִשְׁפָּט הִוא קָדֵשׁ</strong> — "En-mishpat, that is, Kadesh." The parenthetical identification links the obscure battle-site name with the well-known Kadesh-barnea of the wilderness narratives (Num 13:26; 20:1; Deut 1:2) — where Israel camped before the conquest. The coalition\'s route presages the later route of the Exodus-Conquest. <strong>אֵת כָּל-שְׂדֵה הָעֲמָלֵקִי</strong> — "the whole territory of the Amalekites" — Amalek appears as a people long before Esau\'s grandson Amalek of 36:12; the name here may be ethnic rather than eponymous, identifying the pre-Israelite inhabitants of the Negev.</p>',
    "8": '<p>The five Canaanite kings march out to meet the eastern coalition in battle in the Valley of Siddim. The narrative structure is deliberate: after tracing the eastern coalition\'s comprehensive sweep through the Transjordan (vv. 5-7), the five kings emerge to fight — the setup makes clear that the Canaanite armies have been watching a vastly superior force that has already routed every regional power in its path. The battle is practically decided before it begins.</p>',
    "9": '<p>The battle is framed numerically: four kings against five. Despite outnumbering the coalition, the five Canaanite kings lose. The numerical contrast (four vs. five, which should favor the Canaanites) heightens the drama of the defeat and sets up Abram\'s counterintuitive victory with only 318 men (v. 14). The pattern of the few defeating the many — a motif running from Gideon (Judg 7) to David (1 Sam 17) — is anticipated here in embryonic form.</p>',
    "10": '<p><strong>בְּאֵרֹת חֵמָר עֵמֶק הַשִּׂדִּים</strong> — "the Valley of Siddim was full of tar pits." <em>Ḥēmār</em> (bitumen, tar, asphalt) — the same <em>ḥēmār</em> used as the mortar of Babel\'s tower (11:3) and for Moses\'s basket (Exod 2:3). The bitumen pits of the Dead Sea region are archaeologically attested; the valley\'s terrain was treacherous for retreating armies. The fleeing kings of Sodom and Gomorrah fall into the pits — a military disaster that explains how Lot and Sodom\'s goods are taken by the coalition without further resistance.</p>',
    "11": '<p><strong>וַיִּקְחוּ אֶת-כָּל-רְכֻשׁ סְדֹם וַעֲמֹרָה</strong> — "they took all the goods of Sodom and Gomorrah and all their food." <em>Reḵûš</em> (goods, possessions, property) — the term that will describe Abram\'s own wealth (12:5; 15:14); the coalition takes exactly what Lot had been accumulating by living near Sodom. The taking of food (<em>ʾoḵel</em>) alongside goods represents total spoliation — stripping the cities of everything.</p>',
    "12": '<p><strong>וַיִּקְחוּ אֶת-לוֹט וְאֶת-רְכֻשׁוֹ</strong> — "they took Lot and his possessions." Lot, who had chosen the well-watered plain for its wealth, has his wealth taken away along with his person. The irony tracks precisely: the choice of material abundance (13:10-11) leads directly to captivity. <strong>בֶּן-אֲחִי אַבְרָם</strong> (son of Abram\'s brother) — a reminder of the family connection that will motivate Abram\'s rescue; the covenant line\'s kinship-loyalty supersedes the political situation.</p>',
    "13": '<p><strong>אַבְרָם הָעִבְרִי</strong> (<em>ʾaḇrām hāʿiḇrî</em>) — "Abram the Hebrew." <em>Haʿiḇrî</em> is the first use of this designator for Abram — and, notably, it is given by outsiders. <em>ʿIḇrî</em> (Hebrew) derives from <em>ʿāḇar</em> (to cross over, to pass through) and may mean "the one from the other side" (across the Euphrates — consistent with Josh 24:2-3: "your fathers lived beyond the River"). It is an ethnic-territorial label, not a self-designation — Abram is identified as the stranger-from-beyond-the-river. Later, the term <em>ʿiḇrî</em> will be used almost exclusively in contexts where Israelites are identified to non-Israelites (Exod 1:15-16; 2:6, 11; Jon 1:9; Gen 39:14, 17; 40:15; 41:12).</p>',
    "14": '<p><strong>חֲנִיכָיו יְלִידֵי בֵיתוֹ שְׁמֹנָה עָשָׂר וּשְׁלֹשׁ מֵאוֹת</strong> — "his trained men, born in his household, 318." <em>Ḥănîḵîm</em> (trained men, retainers) — from <em>ḥānaḵ</em> (to train, dedicate, initiate), the root of <em>ḥănukkāh</em> (dedication). These are household-born professional fighting men, trained warriors rather than mercenaries. 318 men against the coalition that had just swept the entire Transjordan — the disparity is stark and sets up the miraculous character of the victory. Abram "pursues as far as Dan" — Dan here is the northern limit of later Israelite territory, a geographical note that may use the place-name anachronistically (the city is renamed Dan in Judg 18:29).</p>',
    "15": '<p><strong>וַיַּחֲלֵק עֲלֵיהֶם לַיְלָה</strong> — "he divided his forces against them by night." The night-attack strategy (dividing forces, surprise, darkness) echoes military tactics attested in ancient Near Eastern warfare. <em>Wayyaḥăleq</em> (Piel of <em>ḥālaq</em>, to divide, allot) — the same root as the division of the land (Josh 14:5) and Babel\'s division. Abram pursues "to Hobah, which is north of Damascus" — the pursuit extends far beyond Canaan\'s borders into Syria, indicating either exceptional military success or divine enablement not explicitly narrated.</p>',
    "16": '<p><strong>וַיָּשֶׁב אֵת כָּל-הָרְכוּשׁ</strong> — "he recovered all the goods." The keyword <em>reḵûš</em> (goods/possessions) is recovered completely — the total spoil the coalition had taken (v. 11) is fully restored. <strong>וְגַם אֶת-לוֹט אָחִיו וּרְכֻשׁוֹ הֵשִׁיב</strong> — "and also his relative Lot and his possessions he brought back." The military victory serves the covenant purpose: Lot is rescued so that the family of the promise is preserved. The restoration is complete: people, goods, and women — all that the coalition had taken.</p>',
    "17": '<p><strong>עֵמֶק שָׁוֵה הוּא עֵמֶק הַמֶּלֶךְ</strong> — "the Valley of Shaveh, that is, the King\'s Valley." <em>Šāweh</em> = level/plain; the parenthetical identifies it with the King\'s Valley, which later tradition (2 Sam 18:18) locates near Jerusalem — where Absalom erected his pillar. The meeting of Abram with the king of Sodom and with Melchizedek in the same valley creates a dramatic contrast: the Sodom king offers goods (vv. 21-24); the king-priest of Salem offers bread, wine, and blessing (vv. 18-20).</p>',
    "18": '<p><strong>מַלְכִּי-צֶדֶק מֶלֶךְ שָׁלֵם</strong> (<em>Malkî-ṣeḏeq melek šālēm</em>) — "Melchizedek, king of Salem." The name <em>Malkî-ṣeḏeq</em> = "my king is righteous" or "king of righteousness" — the same components reappear in Ps 110:4 (the Davidic king declared "a priest forever after the order of Melchizedek") and in Hebrews 7 as the key to the new covenant priesthood. <em>Šālēm</em> = "peace/wholeness" — most plausibly Jerusalem (Ps 76:2: "in Salem is his tent") before it received the name Jebus or Jerusalem. <strong>כֹּהֵן לְאֵל עֶלְיוֹן</strong> (<em>kōhēn lĕʾēl ʿelyôn</em>) — "priest of God Most High." Melchizedek holds the dual office of king and priest simultaneously — an office that Israelite law explicitly separated (Uzziah is struck with leprosy for trying it, 2 Chr 26:16-21) but that will be united in the Davidic king (Ps 110:4) and fulfilled in Christ.</p>',
    "19": '<p><strong>בָּרוּךְ אַבְרָם לְאֵל עֶלְיוֹן קֹנֵה שָׁמַיִם וָאָרֶץ</strong> — "blessed be Abram by God Most High, maker/possessor of heaven and earth." <em>Qôneh</em> (Qal participle of <em>qānāh</em>) — a word with two senses: to acquire/possess, and to create (Gen 14:22; Prov 8:22; Deut 32:6). Applied to God with "heaven and earth," both meanings converge: God is both Creator and Possessor of all things. The epithet <em>ʾēl ʿelyôn</em> (God Most High) is the Canaanite/Semitic title Melchizedek uses — which Abram will identify with YHWH in v. 22, equating the pre-Israelite divine name with the covenant name.</p>',
    "20": '<p><strong>וּבָרוּךְ אֵל עֶלְיוֹן אֲשֶׁר-מִגֵּן צָרֶיךָ בְיָדֶךָ</strong> — "and blessed be God Most High, who delivered your enemies into your hand." <em>Migen</em> (Piel of <em>māgan</em>, to deliver, hand over) — the same root as <em>māgēn</em> (shield) in 15:1 ("I am your shield"). <em>ʾĂšer-miggen ṣārêḵā bĕyāḏĕḵā</em> — the deliverance formula that will echo through the Exodus narrative: "I have given [Pharaoh/the kings/the land] into your hand." <strong>וַיִּתֶּן-לוֹ מַעֲשֵׂר מִכֹּל</strong> — "he gave him a tenth of everything." The first tithe in Scripture — Abram voluntarily gives a tenth of the battle spoils to the priest-king. Hebrews 7:9-10 argues that Levi "paid the tithe through Abraham" — the ancestor\'s tithe to a superior priest establishes a precedent for Melchizedek\'s priesthood being greater than the Levitical order.</p>',
    "21": '<p><strong>תֶּן-לִי הַנֶּפֶשׁ וְהָרְכֻשׁ קַח-לָךְ</strong> — "give me the persons and take the goods for yourself." The king of Sodom makes a practical offer: he wants his people back; Abram can keep the goods as a military reward. <em>Nepeš</em> here = persons/lives (the people of Sodom carried off by the coalition). The offer is customary by ancient war-spoils convention — but Abram\'s response will refuse both people and goods to maintain his witness before the LORD.</p>',
    "22": '<p><strong>הֲרִמֹתִי יָדִי אֶל-יְהוָה אֵל עֶלְיוֹן קֹנֵה שָׁמַיִם וָאָרֶץ</strong> — "I have raised my hand to the LORD, God Most High, maker of heaven and earth." <em>Hărîmōtî yāḏî</em> (I have raised my hand) — the oath gesture: lifting the hand toward heaven when swearing (cf. Deut 32:40; Ezek 20:5, 6; Dan 12:7; Rev 10:5-6). Crucially, Abram identifies YHWH with the <em>ʾēl ʿelyôn</em> Melchizedek had named: he equates the Canaanite title Melchizedek used with the covenant name YHWH. This identification is the theological heart of the Melchizedek encounter — the Most High God worshiped by this pre-Israelite priest is the same God who called Abram from Ur.</p>',
    "23": '<p><strong>אִם-מִחוּט וְעַד שְׂרוֹךְ-נַעַל</strong> — "if from a thread to a sandal strap." The merism of smallest (thread) to least valuable-but-functional (sandal strap) expresses total refusal: Abram will take nothing from Sodom\'s king. The reason follows: <strong>לֹא-אַתָּה תֹאמַר הֶעֱשַׁרְתִּי אֶת-אַבְרָם</strong> — "so that you cannot say, \'I made Abram rich.\'" Abram\'s wealth must come from YHWH alone, not from the king of the wicked city. The honor-system logic is precise: accepting Sodom\'s goods would give Sodom\'s king a patron-claim over Abram, crediting him rather than God for Abram\'s prosperity.</p>',
    "24": '<p><strong>בִּלְעָדַי רַק אֲשֶׁר אָכְלוּ הַנְּעָרִים</strong> — "except what the young men have eaten." Abram\'s refusal is complete for himself but not imposed on his allies: Aner, Eshkol, and Mamre (the Amorite confederates of 13:18; 14:13) are entitled to their share of the spoil by the norms of the war-spoils custom. Abram distinguishes between his personal vow (<em>nišbaʿtî</em>, I have sworn) and the rightful claims of his allies. The moral restraint is complete and carefully bounded — not an ascetic rejection of all goods, but a specific refusal tied to a specific oath to YHWH.</p>'
  },
  "15": {
    "1": '<p><strong>אַחַר הַדְּבָרִים הָאֵלֶּה</strong> (<em>ʾaḥar haddĕḇārîm hāʾēlleh</em>) — "after these things." <em>ʾAḥar haddĕḇārîm hāʾēlleh</em> is a recurring narrative connective in Genesis (22:1, 20; 39:7; 40:1; 48:1) that signals a significant event following a major one — the Melchizedek episode and the Sodom-king\'s offer are the preceding context; the covenant ceremony follows.</p><p><strong>אַל-תִּירָא אַבְרָם אָנֹכִי מָגֵן לָךְ</strong> — "do not be afraid, Abram; I am your shield." The divine "do not fear" (<em>ʾal-tîrāʾ</em>) formula is the standard angelic and prophetic reassurance (cf. 26:24; Isa 41:10, 13, 14; 43:1, 5; Dan 10:12, 19). <em>Māgēn</em> (shield) — God as military protector; the same root as <em>māgan</em> in 14:20 ("delivered your enemies"). The shield image is explicitly military: having just refused Sodom\'s goods and made enemies of the Elamite coalition, Abram may fear reprisal. <strong>שְׂכָרְךָ הַרְבֵּה מְאֹד</strong> — "your reward/wages very great." <em>Śāḵār</em> (reward, wages, compensation) — God himself is the reward; the doubled intensifier <em>harbēh mĕʾōḏ</em> is emphatic.</p>',
    "2": '<p><strong>אֲדֹנָי יֱהֹוִה מַה-תִּתֶּן-לִי</strong> — "Sovereign LORD, what will you give me?" The double divine address <em>ʾAḏōnāy YHWH</em> (Lord YHWH) is the form of heightened supplication used in lament and petition (Deut 3:24; Josh 7:7; Judg 6:22; Ezek 2:4; 4:14; Amos 7:2, 5). Abram complains to God — a bold but covenant-legitimate speech act. <strong>וְאָנֹכִי הוֹלֵךְ עֲרִירִי</strong> — "and I am going childless." <em>ʿArîrî</em> (childless, stripped) — from <em>ʿārar</em> (to strip bare, to lay waste); the LXX reads <em>ametatithetos</em>; the word implies desolate barrenness, not merely the absence of children. The heir by default is Eliezer of Damascus — a household servant who would inherit by ANE custom if the master died childless (attested in Nuzi adoption contracts).</p>',
    "3": '<p><strong>בֶּן-בֵּיתִי יוֹרֵשׁ אֹתִי</strong> — "a son of my house will be my heir." <em>Ben-bêtî</em> (son of my house) = household servant; <em>yôrēš</em> (heir, one who inherits) from <em>yāraš</em> (to possess, inherit, dispossess). Abram states the problem plainly: without a biological heir, his estate and the covenant promise will pass through a servant. The word of YHWH must address this directly — which it does in v. 4.</p>',
    "4": '<p><strong>לֹא יִירָשְׁךָ זֶה כִּי-אִם אֲשֶׁר יֵצֵא מִמֵּעֶיךָ</strong> — "this one will not be your heir, but one who comes from your own body." <em>ʾĂšer yēṣēʾ mimmēʿêḵā</em> (who comes forth from your inward parts/loins) — <em>meʿeh</em> (inward parts, bowels, the seat of emotion and reproduction) is the most intimate bodily term possible for biological descent. The promise eliminates the servant-heir category entirely: the covenant passes only through biological offspring.</p>',
    "5": '<p><strong>הַשָּׁמַיְמָה וּסְפֹר הַכּוֹכָבִים</strong> — "look toward the heavens and count the stars." The locative <em>haššāmaymāh</em> (toward-the-heavens, with directional <em>heh</em>) and the imperative <em>sĕpōr</em> (count!) stage a visual-rhetorical challenge: "if indeed you can count them." The night-sky is then announced as the metaphor for the offspring (<em>kōkāḇîm</em>, stars) — the most sublime natural image of innumerability. The star metaphor here complements the dust metaphor of 13:16 and the sand metaphor of 22:17. The LXX follows the MT closely; Paul cites this verse in its LXX form in Rom 4:18.</p>',
    "7": '<p><strong>אֲנִי יְהוָה אֲשֶׁר הוֹצֵאתִיךָ מֵאוּר כַּשְׂדִּים</strong> — "I am the LORD who brought you out of Ur of the Chaldeans." The divine self-identification formula <em>ʾănî YHWH</em> (I am the LORD) is the same as the Sinai declaration of Exod 20:2 ("I am the LORD your God who brought you out of Egypt") — the Ur/Exodus parallelism is structural: YHWH defined himself to Moses by the Exodus just as he defines himself to Abram by Ur. The verb <em>hôṣēʾtî</em> (Hiphil perfect: I brought out, I caused to go out) marks the completed past act of divine election — the calling is already accomplished.</p>',
    "8": '<p><strong>בַּמָּה אֵדַע כִּי אִירָשֶׁנָּה</strong> — "how shall I know that I will inherit it?" Abram asks for a sign — immediately after faith has been credited to him (v. 6). This is not a contradiction but a feature of OT faith: asking for confirmation does not negate trust, it specifies its object. Compare Gideon\'s signs (Judg 6:36-40), Hezekiah\'s sign (2 Kgs 20:8), and Mary\'s question to Gabriel (Luke 1:34) — all are signs requested within the context of genuine faith. God answers not with rebuke but with a covenant ceremony.</p>',
    "9": '<p><strong>קְחָה לִי עֶגְלָה מְשֻׁלֶּשֶׁת</strong> — "take for me a heifer three years old." <em>Mĕšulleššet</em> (three-year-old, tripled) — the animals specified (heifer, goat, ram each three years old, plus a turtledove and young pigeon) represent a combination of large and small animals used in various sacrificial contexts. Three-year-old animals are mature, prime animals. The dove and pigeon pair appears in Leviticus purity offerings (Lev 1:14; 5:7-11) — the entire list suggests a complete sacrifice, not a specific rite. The cutting of the animals (v. 10) is the covenant ceremony.</p>',
    "10": '<p><strong>וַיְבַתֵּר אֹתָם בַּתָּוֶךְ</strong> (<em>waybatter ʾōtām battāweḵ</em>) — "he cut them in two down the middle." <em>Bāttar</em> (to cut in pieces) — a rare verb; the noun <em>bĕtārîm</em> (pieces cut in two) in v. 17 is related. This cutting-in-two is the act that enables the covenant ceremony: the parties pass between the halves, invoking upon themselves the fate of the cut animals if they violate the covenant (cf. Jer 34:18-20: "I will make the men who violated my covenant like the calf they cut in two and then walked between its pieces"). The birds are not cut — a deliberate distinction that has been explained variously (they are too small; the dove/pigeon pair serves a different sacrificial function).</p>',
    "11": '<p><strong>וַיֵּרֶד הָעַיִט עַל-הַפְּגָרִים וַיַּשֵּׁב אֹתָם אַבְרָם</strong> — "birds of prey came down on the carcasses, and Abram drove them away." <em>ʿAyiṭ</em> (birds of prey, raptors) — the vulture/raptor image in the OT often denotes menace and desolation (Job 28:7; Isa 46:11 where the "ravenous bird from the east" = Cyrus; Matt 24:28 / Luke 17:37). Abram actively defends the covenant-sacrifice from defilement — he maintains the integrity of the ceremony even in the gap before God arrives. Some read the birds as a prophetic symbol of the foreign nations that will oppress Israel during the 400-year sojourn.</p>',
    "12": '<p><strong>תַּרְדֵּמָה נָפְלָה עַל-אַבְרָם</strong> (<em>tardēmāh nāplāh ʿal-ʾaḇrām</em>) — "a deep sleep fell upon Abram." <em>Tardēmāh</em> (deep sleep, torpor) — the same word as Adam\'s deep sleep during the creation of the woman (2:21). The word appears in contexts of divine initiative: God acts while the human is unconscious; the sleep signals that the covenant\'s establishment will be entirely divine. <strong>וְאֵימָה חֲשֵׁכָה גְדֹלָה נֹפֶלֶת עָלָיו</strong> — "a great dark terror was falling on him." <em>ʾÊmāh</em> (terror, dread) + <em>ḥăšēḵāh</em> (darkness) + <em>gĕḏōlāh</em> (great) — the triple intensifiers describe the numinous dread of theophanic nearness (cf. Exod 20:18-21; the disciples\' fear at the transfiguration, Matt 17:6; Ezekiel\'s face-down prostration, Ezek 1:28).</p>',
    "13": '<p><strong>יָדֹעַ תֵּדַע כִּי-גֵר יִהְיֶה זַרְעֲךָ</strong> — "know with certainty that your offspring will be sojourners." The infinitive absolute <em>yādōaʿ tēḏaʿ</em> (know truly, surely know) — emphatic double of the same root, conveying absolute certainty. What follows is direct prophecy: 400 years of sojourning in a foreign land, slavery, and oppression. <em>Gēr</em> (sojourner, resident alien) — the status Abram himself inhabits in Canaan (17:8; 23:4; Ps 105:12). The offspring will be sojourners in someone else\'s land — Egypt — as Abram is a sojourner in Canaan. The parallel is intentional.</p>',
    "14": '<p><strong>וְגַם אֶת-הַגּוֹי אֲשֶׁר יַעֲבֹדוּ דָּן אָנֹכִי</strong> — "but also the nation whom they serve I will judge." <em>Dān ʾānōḵî</em> (I will judge) — the same verb root as the name Dan (Judg 5:10). God promises to judge the enslaving nation — the Exodus will be an act of divine justice against Egypt, not merely rescue of Israel. <strong>וְאַחֲרֵי-כֵן יֵצְאוּ בִּרְכֻשׁ גָּדוֹל</strong> — "afterward they will come out with great possessions." The Exodus plunder of Egypt (Exod 12:35-36) is prophesied here, 400 years before it happens — the vocabulary (<em>reḵûš</em>, goods) echoes the same word used for Abram\'s wealth in 13:2 and the Sodom spoils in 14:11-12.</p>',
    "15": '<p><strong>וְאַתָּה תָּבוֹא אֶל-אֲבֹתֶיךָ בְּשָׁלוֹם</strong> — "but you, you will go to your fathers in peace." The personal promise to Abram contrasts with the collective fate of his offspring: they will suffer for 400 years; he will die in peace. <em>ʾEl-ʾăḇōteḵā</em> (to your fathers) is an expression for dying and being gathered to the ancestors — the clan-death formula that implies connection beyond death. <strong>תִּקָּבֵר בְּשֵׂיבָה טוֹבָה</strong> — "you will be buried at a good old age." <em>Śêḇāh ṭôḇāh</em> (good old age, a ripe old age) — the covenant life fulfillment formula; Abram dies at 175 (25:7-8) "at a ripe old age, an old man and satisfied with years" — the precise fulfillment of this promise.</p>',
    "16": '<p><strong>וְדוֹר רְבִיעִי יָשׁוּבוּ הֵנָּה</strong> — "and in the fourth generation they will return here." The "400 years" of v. 13 and the "fourth generation" here have generated considerable discussion: a generation of 100 years would make four generations = 400 years (and the Exodus genealogy for Moses in Exod 6:16-20 is compressed to four generations from Levi). <strong>כִּי לֹא-שָׁלֵם עֲוֹן הָאֱמֹרִי עַד-הֵנָּה</strong> — "for the sin of the Amorites is not yet full." <em>Šālēm</em> (complete, full) — moral completion as the trigger for judgment. God delays Israel\'s possession of Canaan by 400 years because the Canaanites\' sin has not yet "ripened." The divine patience extends even to the wicked: judgment awaits the full measure of guilt. This principle also implies a moral dimension to the conquest: Israel displaces Canaan not arbitrarily but as a judgment on specific, fully-developed wickedness.</p>',
    "17": '<p><strong>תַּנּוּר עָשָׁן וְלַפִּיד אֵשׁ אֲשֶׁר עָבַר בֵּין הַגְּזָרִים הָאֵלֶּה</strong> — "a smoking furnace and a blazing torch that passed between these pieces." The theophanic fire symbols — <em>tannûr ʿāšān</em> (smoking furnace/brazier) and <em>lappîḏ ʾēš</em> (torch of fire) — represent the divine presence. The divine fire is also the wilderness pillar (Exod 13:21-22), the Sinai theophany (Exod 19:18; Deut 4:11-12), and the Shekinah (1 Kgs 8:10-11). Critically, only the fire-symbols pass between the pieces — Abram is asleep (v. 12). The covenant is entirely divine in initiation, execution, and guarantee: YHWH alone walks between the animal halves, placing the covenant obligation entirely on himself. This unilateral structure is the grammar of grace — the Abrahamic covenant\'s unconditional character rests on God\'s self-commitment alone.</p>',
    "18": '<p><strong>כָּרַת יְהוָה אֶת-אַבְרָם בְּרִית</strong> (<em>kārat YHWH ʾet-ʾaḇrām bĕrît</em>) — "the LORD cut a covenant with Abram." <em>Kārat bĕrît</em> (to cut a covenant) — the idiom derives from the cutting of the animals in the ceremony (vv. 9-10): to cut a covenant is to perform the sacrifice that ratifies it. The land boundaries follow: from <em>naḥal miṣrāyim</em> (the brook/wadi of Egypt, likely the Wadi el-Arish on the Sinai border) to the Euphrates — the full extent of the Davidic-Solomonic empire (1 Kgs 4:21; 8:65). The covenant land exceeds what Israel ever controlled in history, pointing the promise toward an eschatological fulfillment.</p>',
    "19": '<p>The <strong>קֵינִי</strong> (Kenites), <strong>קְנִזִּי</strong> (Kenizzites), and <strong>קַדְמֹנִי</strong> (Kadmonites) are listed first in the ten-nation land-promise list. The Kenites appear later as allies of Israel (Judg 1:16; 4:11, 17; 5:24; 1 Sam 15:6). The Kenizzites are associated with Caleb\'s clan (Num 32:12; Josh 14:6, 14) — Caleb "the Kenizzite" receives Hebron as his inheritance, the very city of Abram\'s altar (13:18). The list of ten peoples is broader than the standard seven-nation list of the Conquest period (Deut 7:1; Josh 3:10), suggesting an original land promise of greater scope than what the Conquest actually reached.</p>',
    "20": '<p>The <strong>חִתִּי</strong> (Hittites), <strong>פְּרִזִּי</strong> (Perizzites), and <strong>רְפָאִים</strong> (Rephaim) continue the land-promise list. The Hittites appear in Abram\'s own lifetime as the sellers of the Machpelah cave (ch. 23 — Ephron the Hittite); the Perizzites are among the Canaanite peoples whose territory will be Israelite territory (Exod 3:8, 17). The Rephaim appear already as a conquered people in ch. 14 (v. 5) — the covenant land includes territory that even the eastern coalition had swept through.</p>',
    "21": '<p>The final group in the land-promise list: <strong>אֱמֹרִי</strong> (Amorites, the highland Canaanites whose sin is "not yet full" in v. 16), <strong>כְּנַעֲנִי</strong> (Canaanites), <strong>גִּרְגָּשִׁי</strong> (Girgashites), and <strong>יְבוּסִי</strong> (Jebusites — the pre-Israelite inhabitants of Jerusalem). The ten-nation list frames the promised land as the entire territory of the pre-existing peoples — the Abrahamic covenant is simultaneously a land-grant and a judgment oracle. The moral framework of v. 16 (the Amorites\' sin not yet full) prevents the land-promise from being mere territorial ambition: the transfer of the land is grounded in divine moral justice, not ethnic favoritism.</p>'
  },
  "16": {
    "1": '<p><strong>שָׂרַי אֵשֶׁת אַבְרָם לֹא יָלְדָה לוֹ</strong> — "Sarai, wife of Abram, had not borne him children." The opening statement echoes 11:30 (Sarai was barren), restating the problem that the covenant promise of ch. 15 has not resolved. <strong>שִׁפְחָה מִצְרִית</strong> (<em>šipḥāh miṣrît</em>, Egyptian slave) — Hagar is identified by legal status and ethnicity. She is a <em>šipḥāh</em> (female slave, personal maid-servant) — legally subordinate to Sarai. The irony of her Egyptian identity is notable: she is presumably one of the servants acquired during the Egypt sojourn (12:16), making the covenant couple\'s Egyptian interlude have an ongoing consequence in their household.</p>',
    "2": '<p><strong>עֲצָרַנִי יְהוָה מִלֶּדֶת</strong> (<em>ʿăṣāranî YHWH milleḏet</em>) — "the LORD has shut me up from bearing." <em>ʿĀṣar</em> (to shut up, close, restrain) — the same verb applied to the LORD closing wombs in 1 Sam 1:5-6 (Hannah) and elsewhere. Sarai attributes her barrenness directly to divine action — a theologically significant claim that neither narrator nor God challenges. <strong>אִבָּנֶה מִמֶּנָּה</strong> (<em>ʾibbāneh mimmennāh</em>, I will be built up through her) — the idiom for having children that plays on <em>bānāh</em> (build) and <em>bēn</em> (son): sons "build up" the family; to be barren is to be without a building, a demolished house. The surrogate-wife practice is attested in the Nuzi tablets (c. 1500-1400 BCE) and Code of Hammurabi §146: a wife who gives her slave to her husband for offspring retains legal superiority over the slave even after the birth.</p>',
    "3": '<p><strong>וַתִּקַּח שָׂרַי אֵשֶׁת-אַבְרָם אֶת-הָגָר הַמִּצְרִית שִׁפְחָתָהּ</strong> — Sarai is the grammatical subject: she takes, she gives. Abram is the passive recipient of his wife\'s initiative. <strong>לְאַבְרָם אִישָׁהּ לוֹ לְאִשָּׁה</strong> — "to Abram her husband as a wife." <em>Lĕʾiššāh</em> (as a wife) — Hagar\'s legal status is temporarily elevated from <em>šipḥāh</em> (slave) to <em>ʾiššāh</em> (wife, secondary); she acquires wife-status specifically for the purpose of producing an heir. After the birth, the tension with Sarai will force a renegotiation of this status (vv. 4-6; 21:10).</p>',
    "4": '<p><strong>וַתַּהַר וַתֵּרֶא כִּי הָרָתָה וַתֵּקַל גְּבִרְתָּהּ בְּעֵינֶיהָ</strong> — "she conceived, and when she saw that she had conceived, her mistress became light in her eyes." <em>Tēqal</em> (Qal imperfect of <em>qālal</em>, to be light, slight, contemptible) — from <em>qālal</em>, the opposite of <em>kāḇēḏ</em> (to be heavy/honored). Hagar honors her mistress less once she is pregnant — the pregnancy shifts the honor balance: the fertile servant now has something the barren mistress does not. The social dynamics of shame and honor are explicit: fertility is honor; barrenness is shame; Hagar\'s pregnancy reverses the conventional hierarchy.</p>',
    "5": '<p><strong>חֲמָסִי עָלֶיךָ</strong> (<em>ḥāmāsî ʿālêḵā</em>) — "my wrong/violence is upon you." <em>Ḥāmās</em> (violence, wrongdoing, injustice) is a strong moral-legal term: it denotes the wickedness that filled the earth before the Flood (6:11, 13), the crime of false witnesses (Exod 23:1), and the violent oppression that the prophets condemn (Isa 53:9; Jer 6:7; Ezek 7:23; Amos 3:10; Hab 1:2-3). Sarai uses the most loaded moral language available to accuse Abram of wrongdoing. <strong>יִשְׁפֹּט יְהוָה בֵּינִי וּבֵינֶיךָ</strong> — "the LORD judge between me and you" — Sarai invokes divine judgment on a domestic dispute, framing it as a legal matter before the covenant God.</p>',
    "6": '<p><strong>עַשִׂי-לָהּ הַטּוֹב בְּעֵינָיִךְ</strong> — "do with her what is good in your eyes." Abram refuses to adjudicate and gives the decision back to Sarai — a moral abdication that parallels his silence during the Egypt episode (12:10-20). <em>Wayyîraʿ ʾōtāh Śāray</em> — "Sarai mistreated/afflicted her." <em>ʿĀnāh</em> (Piel: to afflict, oppress, humble) — the same verb used for Egypt\'s oppression of Israel (Exod 1:11, 12; Deut 26:6) and for the affliction the LORD predicts for Abram\'s descendants (15:13: <em>wĕʿinnû ʾōtām</em>). Sarai\'s treatment of the Egyptian slave Hagar becomes an ironic anticipation of Egypt\'s treatment of the Hebrew slaves — and Hagar\'s flight anticipates the Exodus.</p>',
    "7": '<p><strong>וַיִּמְצָאָהּ מַלְאַךְ יְהוָה עַל-עֵין הַמַּיִם</strong> — "the angel of the LORD found her at a spring of water." <em>Malʾaḵ YHWH</em> (the angel of the LORD) — the first appearance of this figure in the OT. The phrase presents a theologically complex figure: in the narrative, the angel speaks as YHWH (v. 10: "I will greatly multiply your offspring"), and Hagar identifies the one who spoke with <em>ʾēl rōʾî</em> (the God who sees me, v. 13). The angel appears to act with divine authority and is addressed as God — the pattern continues throughout the OT (Judg 6:11-23; 13:2-23; Exod 3:2-6). The encounter with Hagar, an Egyptian slave fleeing into the desert, establishes the theological principle that YHWH\'s care extends beyond the covenant family.</p>',
    "8": '<p><strong>מִזֶּה בָאת וְאָנָה תֵלֵכִי</strong> — "where have you come from and where are you going?" The double interrogation parallels God\'s questions to Adam ("where are you?" 3:9), to Cain ("where is Abel your brother?" 4:9), to Elijah ("what are you doing here, Elijah?" 1 Kgs 19:9, 13). The divine questions in the OT are not requests for information — the questioner knows — but are invitations to self-reflection and honest speech. Hagar\'s answer is honest: she is fleeing from her mistress. The angel does not rebuke her for the admission.</p>',
    "9": '<p><strong>שׁוּבִי אֶל-גְּבִרְתֵּךְ וְהִתְעַנִּי תַּחַת יָדֶיהָ</strong> — "return to your mistress and submit under her hands." The command is morally difficult: Hagar is told to return to the source of her oppression. <em>Hitchannî</em> (Hithpael of <em>ʿānāh</em>, to humble yourself, submit) — the same root as the affliction of v. 6 (Sarai <em>ʿinnatāh</em>, afflicted her). Hagar is told to accept the humbling. The command is accompanied by a promise (v. 10) that makes the submission meaningful — not resignation to oppression but trust in divine provision beyond the immediate hardship.</p>',
    "10": '<p><strong>הַרְבָּה אַרְבֶּה אֶת-זַרְעֵךְ</strong> (<em>harbāh ʾarbbeh ʾet-zarʿēḵ</em>) — "I will greatly multiply your offspring." The infinitive absolute construction (same root doubled: <em>harbāh ʾarbbeh</em>) exactly parallels the offspring-multiplication promise to Abram (17:2; 22:17) and to Israel (Exod 1:7). Hagar receives the same promissory formula as the covenant patriarch — her descendants will be multiplied by divine commitment. This is extraordinary: a Gentile slave woman receives a form of the Abrahamic promise. <em>Zaraʿ</em> (offspring/seed) — the same collective noun as 3:15 and all the Abrahamic offspring promises.</p>',
    "11": '<p><strong>יִשְׁמָעֵאל</strong> (<em>Yišmaʿēʾl</em>, Ishmael) — the name is a sentence: "God will hear" or "God has heard" (<em>šāmaʿ</em> + <em>ʾēl</em>). The naming-reason is explicit: <em>kî-šāmaʿ YHWH ʾel-ʿonyēḵ</em> (for the LORD has heard your affliction/misery). <em>ʿOnî</em> (misery, affliction) — the same root as <em>ʿānāh</em> (to afflict) in vv. 6, 9. YHWH heard the affliction that Sarai caused (and that the LORD-directed sojourn indirectly produced through the Egypt episode). The name Ishmael encodes a theology of divine hearing extended to those outside the covenant line: God hears the slave.</p>',
    "12": '<p><strong>פֶּרֶא אָדָם</strong> (<em>pereh ʾāḏām</em>, a wild-ass man) — <em>Pereʾ</em> is the wild ass of the steppe, whose freedom and defiance of domestication is celebrated in Job 39:5-8 ("I let the wild donkey go free; I untied its ropes; who gave the wild donkey its freedom? ... It ranges the hills for its pasture and searches for any green thing"). Ishmael will be untamed and free — a positive quality, not an insult. <strong>יָדוֹ בַכֹּל וְיַד כֹּל בּוֹ</strong> — "his hand against everyone and everyone\'s hand against him" — the wild-ass freedom manifests as universal conflict; Ishmael will be a fighting people, hostile to and hostiled by all. The oracle describes the Ishmaelite/Bedouin peoples of the desert, not a moral condemnation of Ishmael as an individual.</p>',
    "13": '<p><strong>אַתָּה אֵל רֳאִי</strong> (<em>ʾattāh ʾēl rōʾî</em>) — "You are El-Roi, the God of seeing/who sees me." Hagar gives God a name — one of the few instances where a human names God in the OT (cf. Abraham\'s <em>YHWH-Yireh</em> in 22:14). <em>Rāʾāh</em> (to see) — God saw Hagar in her affliction and heard (<em>šāmaʿ</em>) — the divine seeing and hearing form the theological content of the divine name she coins. <strong>הֲגַם הֲלֹם רָאִיתִי אַחֲרֵי רֹאִי</strong> — "Have I actually seen here the one who sees me?" The Hebrew is difficult (literally: "after the one who sees me / have I also here seen?") — Hagar is astonished that she has seen God (or the divine representative) and survived; seeing God face-to-face was considered potentially fatal (Exod 33:20; Judg 6:22-23; 13:22).</p>',
    "14": '<p><strong>בְּאֵר לַחַי רֹאִי</strong> (<em>Bĕʾēr laḥay rōʾî</em>) — "the well of the Living One who sees me." The sanctuary name encodes the entire theophanic encounter: God is living (<em>laḥay</em>, the Living One), and he sees (<em>rōʾî</em>). The well becomes a named site that preserves the memory of YHWH\'s care for Hagar. It appears again in 24:62 (Isaac comes from there) and 25:11 (Isaac settled near it after Abraham\'s death) — the site of Hagar\'s theophany becomes part of the Isaacite landscape, without narrative commentary on the irony.</p>',
    "15": '<p><strong>וַתֵּלֶד הָגָר לְאַבְרָם בֵּן</strong> — "Hagar bore to Abram a son." The birth is stated simply — the promised offspring arrives, though not the covenant offspring. <strong>וַיִּקְרָא אַבְרָם שֶׁם-בְּנוֹ אֲשֶׁר-יָלְדָה הָגָר יִשְׁמָעֵאל</strong> — Abram names the son Ishmael, fulfilling the angel\'s instruction (v. 11). The naming by Abram gives Ishmael patriarchal recognition — he is Abram\'s son, legally and socially, even if not the covenant heir. Abram\'s paternal act accepts responsibility for the child produced by Sarai\'s initiative and his own compliance.</p>',
    "16": '<p><strong>וְאַבְרָם בֶּן-שְׁמֹנִים שָׁנָה וְשֵׁשׁ שָׁנִים</strong> — "and Abram was eighty-six years old when Hagar bore Ishmael." The chronological note anchors the birth of Ishmael precisely: 86 years old for Abram, ten years after arriving in Canaan (16:3). The covenant promise of a son (15:4) remains unfulfilled for another 13 years (17:1: Abram is 99 when God next speaks; 17:25: Ishmael is 13 at the circumcision). The thirteen-year silence of YHWH between Ishmael\'s birth and the covenant of circumcision is not narrated — the narrator leaves it as an implied gap, a period of Abram living with the Ishmael solution as if it were sufficient.</p>'
  }
}

